	private static SketchBasedJoinEstimator.SketchPlannerPath unsupportedPath(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern || tupleExpr instanceof BindingSetAssignment) {
			return SketchBasedJoinEstimator.SketchPlannerPath.UNSUPPORTED_SHAPE;
		}
		if (tupleExpr instanceof Filter filter && unwrapFilterPattern(filter) != null) {
			return SketchBasedJoinEstimator.SketchPlannerPath.UNSUPPORTED_SHAPE;
		}
		return SketchBasedJoinEstimator.SketchPlannerPath.UNSUPPORTED_WRAPPER;
	}

	private static StatementPattern unwrapFilterPattern(Filter filter) {
		TupleExpr argument = filter.getArg();
		if (argument instanceof StatementPattern) {
			return (StatementPattern) argument;
		}
		if (argument instanceof Filter) {
			return unwrapFilterPattern((Filter) argument);
		}
		return null;
	}

	static String describeExprOrder(List<TupleExpr> expressions) {
		List<String> described = new ArrayList<>(expressions.size());
		for (TupleExpr expression : expressions) {
			described.add(describeTupleExpr(expression));
		}
		return described.toString();
	}

	static String describeTupleExpr(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern statementPattern) {
			return "SP(" + describeVar(statementPattern.getSubjectVar()) + ' '
					+ describeVar(statementPattern.getPredicateVar()) + ' '
					+ describeVar(statementPattern.getObjectVar())
					+ (statementPattern.getContextVar() == null ? ""
							: ' ' + describeVar(statementPattern.getContextVar()))
					+ ')';
		}
		if (tupleExpr instanceof BindingSetAssignment assignment) {
			int rows = 0;
			for (Object ignored : assignment.getBindingSets()) {
				rows++;
			}
			return "BSA(names=" + new TreeSet<>(assignment.getBindingNames()) + ", rows=" + rows + ')';
		}
		if (tupleExpr instanceof Filter filter) {
			return "Filter(" + describeTupleExpr(filter.getArg()) + "; " + filter.getCondition() + ')';
		}
		return tupleExpr.getClass().getSimpleName() + '(' + tupleExpr + ')';
	}

	private static String describeVar(Var var) {
		if (var == null) {
			return "null";
		}
		if (!var.hasValue()) {
			return '?' + Objects.toString(var.getName(), "_");
		}
		Value value = var.getValue();
		return value == null ? '?' + Objects.toString(var.getName(), "_") : value.stringValue();
	}

